// Method A (Double Loop)
bool hasDuplicateA(int arr[], int n) {
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j < n; j++)
            if (arr[i] == arr[j]) return true;
    return false;
}

// Method B (Auxiliary Data Structure)
bool hasDuplicateB(int arr[], int n) {
    std::unordered_set<int> s;
    for (int i = 0; i < n; i++) {
        if (s.count(arr[i])) return true;
        s.insert(arr[i]);
    }
    return false;
}

// Function A
int fibA(int n) {
    if (n <= 1) return n;
    return fibA(n - 1) + fibA(n - 2);
}

// Function B
int fibB(int n) {
    int f[n + 1];
    f[0] = 0; f[1] = 1;
    for (int i = 2; i <= n; i++)
        f[i] = f[i - 1] + f[i - 2];
    return f[n];
}
